    'pages.skema.auth-dan-middleware.heading_3' => 'Proteksi Route di Proyek',
    'pages.skema.auth-dan-middleware.heading_4' => 'Middleware Custom: SetLocale',
    'pages.skema.auth-dan-middleware.heading_5' => 'Checklist Security Minimum',
    'pages.skema.auth-dan-middleware.heading_6' => 'Matrix Middleware (Praktis)',
    'pages.skema.auth-dan-middleware.heading_7' => 'Standar Tim (Strict) Auth',
    'pages.skema.auth-dan-middleware.item_1' => 'Fallback 404 ditempatkan di luar auth agar respons error tetap konsisten.',
    'pages.skema.auth-dan-middleware.item_2' => 'Pastikan route sensitif selalu berada di middleware <code>auth</code>.',
    'pages.skema.auth-dan-middleware.item_3' => 'Validasi redirect dan guard flow saat login/logout agar tidak ada open redirect.',
    'pages.skema.auth-dan-middleware.item_4' => 'Uji skenario guest vs authenticated untuk setiap halaman blueprint baru.',
    'pages.skema.auth-dan-middleware.item_5' => '<code>/dashboard</code> memakai middleware <code>auth</code> + <code>verified</code>.',
    'pages.skema.auth-dan-middleware.item_6' => 'Semua route generator di <code>routes/menu.php</code> dibungkus middleware <code>auth</code>.',
    'pages.skema.auth-dan-middleware.item_7' => 'Profile management di <code>routes/web.php</code> juga ada dalam group <code>auth</code>.',
    'pages.skema.auth-dan-middleware.item_8' => 'Untuk area kritikal, tambahkan <code>verified</code> atau middleware tambahan lain sesuai kebutuhan.',
    'pages.skema.auth-dan-middleware.item_9' => 'Gunakan <code>signed</code> dan <code>throttle</code> seperti pada route verifikasi email.',
    'pages.skema.auth-dan-middleware.lead' => 'Pondasi keamanan proyek: route auth bawaan Laravel + proteksi middleware + middleware custom locale.',
    'pages.skema.auth-dan-middleware.note_1' => 'Dampak: user belum login tidak bisa akses halaman konten internal di bawah <code>resources/views/pages</code>.',
    'pages.skema.auth-dan-middleware.step_1' => '2. Submit login ke <code>POST /login</code>.',
    'pages.skema.auth-dan-middleware.step_2' => '3. Jika sukses, session auth aktif dan user diarahkan ke halaman aplikasi.',
    'pages.skema.auth-dan-middleware.step_3' => '4. Route protected (dashboard/menu pages) hanya bisa dibuka jika lolos middleware <code>auth</code>.',
    'pages.skema.auth-dan-middleware.step_4' => '5. Route tertentu juga pakai <code>verified</code> untuk email verification.',
    'pages.skema.auth-dan-middleware.step_5' => '<strong>Rule wajib:</strong> endpoint sensitif harus punya throttle jika rawan abuse.',
    'pages.skema.auth-dan-middleware.step_6' => '<strong>Rule wajib:</strong> tidak boleh expose detail autentikasi internal pada pesan error user.',
    'pages.skema.auth-dan-middleware.step_7' => '<strong>Rule wajib:</strong> setiap perubahan auth flow harus diuji guest, user valid, dan user tanpa verifikasi.',
    'pages.skema.auth-dan-middleware.step_8' => '1. Guest akses <code>/login</code> (dari <code>routes/auth.php</code>).',
    'pages.skema.auth-dan-middleware.step_9' => '<strong>Rule wajib:</strong> route baru harus diklasifikasikan jelas: public vs auth vs auth+verified.',
    'pages.skema.auth-dan-middleware.warn_1' => 'Middleware ini berjalan di group <code>web</code>, jadi seluruh request web otomatis mengikuti locale session.',
