    'pages.skema.data-layer.item_19' => '<code>database/seeders/*</code> dan <code>database/factories/*</code> untuk data awal/testing.',
    'pages.skema.data-layer.item_2' => '<code>database/migrations/*</code> untuk versi skema tabel.',
    'pages.skema.data-layer.item_20' => '<code>app/Providers/AppServiceProvider.php</code> untuk guard global (misal strict mode, lazy loading policy).',
    'pages.skema.data-layer.item_21' => 'Jika ada side effect eksternal (email, webhook), trigger setelah transaction sukses.',
    'pages.skema.data-layer.item_22' => 'Tambahkan logging kontekstual (user id, tenant id, request id) saat exception data layer.',
    'pages.skema.data-layer.item_23' => 'Simpan logic query reusable di local scope (misal <code>scopeActive()</code>, <code>scopeForTenant()</code>) agar tetap testable.',
    'pages.skema.data-layer.item_3' => 'Gunakan nama relasi eksplisit dan konsisten dengan domain bisnis.',
    'pages.skema.data-layer.item_4' => 'Hindari menaruh logic presentasi di model.',
    'pages.skema.data-layer.item_5' => 'Gunakan factory untuk membangun graph data relasi secara konsisten.',
    'pages.skema.data-layer.item_6' => 'Seeder & Factory Strategy',
    'pages.skema.data-layer.item_7' => 'Pisahkan seeder demo/testing agar tidak tercampur dengan seed production.',
    'pages.skema.data-layer.item_8' => 'Gunakan factory untuk membangun graph data relasi secara konsisten.',
    'pages.skema.data-layer.item_9' => 'Bungkus proses tulis multi-tabel dengan <code>DB::transaction()</code>.',
    'pages.skema.data-layer.lead' => 'Struktur model, relasi, migration, seeder, dan pattern query yang dipakai proyek.',
    'pages.skema.data-layer.code_1' => 'Contoh relasi inti:',
    'pages.skema.data-layer.note_1' => 'Kombinasi index harus mengikuti query real, bukan sekadar menambah index sebanyak mungkin.',
    'pages.skema.data-layer.step_1' => '2. Query dieksekusi lewat model/scope/query object.',
    'pages.skema.data-layer.step_2' => '3. Loading relasi harus dikendalikan (selective eager loading).',
    'pages.skema.data-layer.step_10' => 'Ekstrak filter dinamis ke scope/query object agar controller tetap ringkas dan mudah diuji.',
    'pages.skema.data-layer.step_11' => '2. Migration punya index dan foreign key yang relevan.',
    'pages.skema.data-layer.step_12' => '3. Query list wajib select kolom minimal + pagination + eager loading yang relevan.',
    'pages.skema.data-layer.step_13' => '4. Operasi tulis multi-entity menggunakan transaction.',
    'pages.skema.data-layer.step_14' => '5. Seeder/factory cukup untuk local dev dan test case utama.',
    'pages.skema.data-layer.step_15' => '6. Tidak ada N+1 dan tidak ada query berat tanpa batasan.',
    'pages.skema.data-layer.step_16' => '<strong>Rule wajib:</strong> endpoint list harus pakai pagination; unbounded fetch dilarang.',
    'pages.skema.data-layer.step_17' => '<strong>Rule wajib:</strong> maksimal <code>3 eager relations</code> per query default (kecuali ada justifikasi di PR).',
    'pages.skema.data-layer.step_18' => '<strong>Rule wajib:</strong> maksimal <code>2 level nested eager loading</code> agar kompleksitas query terkendali.',
    'pages.skema.data-layer.step_19' => '<strong>Rule wajib:</strong> operasi tulis multi-tabel atau kritikal konsistensi harus di dalam <code>DB::transaction()</code>.',
    'pages.skema.data-layer.step_20' => '<strong>Rule wajib:</strong> side effect eksternal (email, webhook, dispatch queue) dieksekusi setelah commit transaction.',
    'pages.skema.data-layer.step_21' => '<strong>Rule wajib:</strong> query di dalam loop dilarang kecuali ada batasan terukur dan terdokumentasi.',
    'pages.skema.data-layer.step_22' => '<strong>Rule opsional:</strong> gunakan query cache hanya untuk data read-heavy yang stabil dengan strategi invalidasi jelas.',
    'pages.skema.data-layer.step_23' => '2. Sertakan bukti tidak ada N+1 pada endpoint yang diubah.',
    'pages.skema.data-layer.step_24' => '3. Jika melewati batas eager relations/depth, wajib ada justifikasi teknis yang jelas di PR.',
    'pages.skema.data-layer.step_25' => '4. Untuk proses finansial/stok, jelaskan batas transaction dan strategi concurrency secara eksplisit.',
    'pages.skema.data-layer.step_26' => '5. Pastikan migration rollback aman sebelum merge.',
    'pages.skema.data-layer.step_27' => '1. Request masuk -> controller/use-case validasi input.',
    'pages.skema.data-layer.step_28' => '1. Jelaskan impact query dan index baru pada deskripsi PR.',
    'pages.skema.data-layer.step_29' => 'Migration harus idempotent dan mudah ditelusuri (satu perubahan skema per migration).',
    'pages.skema.data-layer.step_3' => '4. Data dibentuk ke response/view resource.',
    'pages.skema.data-layer.step_30' => 'Pakai <code>select()</code> kolom minimal untuk endpoint list.',
    'pages.skema.data-layer.step_31' => '1. Model dan relasi sudah mencerminkan domain, bukan sekadar tabel.',
    'pages.skema.data-layer.step_32' => '<strong>Rule wajib:</strong> kolom yang dipakai untuk filter, sort, join, dan foreign key harus memiliki index yang sesuai.',
    'pages.skema.data-layer.step_4' => '5. Operasi tulis kritikal dibungkus transaction.',
    'pages.skema.data-layer.step_5' => 'Tambahkan index saat menambah kolom yang dipakai filter/sort/join.',
    'pages.skema.data-layer.step_6' => 'Gunakan foreign key untuk menjaga integritas data, termasuk aturan on update/delete yang tepat.',
    'pages.skema.data-layer.step_7' => 'Pisahkan perubahan berisiko tinggi (rename/drop kolom besar) ke migration terpisah dan window rilis khusus.',
    'pages.skema.data-layer.step_8' => 'Pakai <code>with()</code> atau <code>withCount()</code> untuk mencegah N+1 pada endpoint list/detail.',
    'pages.skema.data-layer.step_9' => 'Pakai pagination untuk dataset besar; hindari memuat semua data ke memori.',
    'pages.skema.data-layer.warn_1' => 'Hindari pola query dalam loop (<code>N+1</code>). Jika menemukan query tambahan per item, evaluasi eager loading.',
    'pages.skema.data-layer.warn_2' => 'Jika satu use-case menghasilkan lebih dari satu perubahan tabel penting, default-nya harus memakai transaction.',
    'pages.skema.error-handling-dan-fallback.chip_1' => 'stability',
