    'pages.skema.layout.heading_1' => 'Flow Render Halaman',
    'pages.skema.layout.heading_2' => 'Struktur Folder Kunci',
    'pages.skema.layout.heading_3' => 'Pola Standar Halaman',
    'pages.skema.layout.heading_4' => 'Peran Section di Layout',
    'pages.skema.layout.heading_5' => 'Checklist Saat Membuat Layout/Page Baru',
    'pages.skema.layout.heading_6' => 'Anti-Pattern Layout',
    'pages.skema.layout.heading_7' => 'Standar Tim (Strict) Layout',
    'pages.skema.layout.item_1' => '<code>@@section(\'styles\')</code>: CSS khusus halaman.',
    'pages.skema.layout.item_10' => 'Menaruh logika bisnis di view/layout.',
    'pages.skema.layout.item_11' => 'Mengcopy-paste blok header/sidebar alih-alih memanggil partial.',
    'pages.skema.layout.item_12' => 'Menggunakan CSS inline berlebihan untuk override cepat tanpa dokumentasi.',
    'pages.skema.layout.item_13' => 'Memuat semua JS plugin di global layout meski dipakai sedikit halaman.',
    'pages.skema.layout.item_2' => '<code>@@section(\'toolbar\')</code>: breadcrumb, title konteks, action button.',
    'pages.skema.layout.item_3' => '<code>@@section(\'content\')</code>: isi utama halaman.',
    'pages.skema.layout.item_4' => '<code>@@section(\'scripts\')</code>: JS vendor/custom khusus halaman.',
    'pages.skema.layout.item_5' => 'Pilih base layout yang tepat (umumnya <code>layouts.index</code>).',
    'pages.skema.layout.item_6' => 'Pastikan section <code>toolbar</code> dan <code>content</code> terdefinisi dengan jelas.',
    'pages.skema.layout.item_7' => 'Gunakan partial yang sudah ada sebelum membuat markup baru.',
    'pages.skema.layout.item_8' => 'Tambahkan styles/scripts hanya bila dibutuhkan halaman tersebut.',
    'pages.skema.layout.item_9' => 'Uji di desktop dan mobile untuk memastikan sidebar/header/drawer tetap sinkron.',
    'pages.skema.layout.lead' => 'Alur struktur layout dari base template, partial, toolbar, sampai konten halaman di Metronic Laravel.',
    'pages.skema.layout.note_1' => 'Pola ini menjaga konsistensi breadcrumb, spacing, dan struktur visual di seluruh halaman.',
    'pages.skema.layout.step_1' => '2. Halaman mewarisi base layout dengan <code>@@extends(\'layouts.index\')</code>.',
    'pages.skema.layout.step_2' => '3. Layout utama memuat partial global: header, sidebar, footer, drawer, script.',
    'pages.skema.layout.step_3' => '4. Section halaman (<code>styles</code>, <code>toolbar</code>, <code>content</code>, <code>scripts</code>) disuntik ke slot layout.',
    'pages.skema.layout.step_4' => '5. Komponen Metronic JS mengaktivasi behavior menu, drawer, tooltip, dan widget.',
    'pages.skema.layout.step_5' => '<strong>Rule wajib:</strong> section <code>toolbar</code> dan <code>content</code> harus eksplisit.',
    'pages.skema.layout.step_6' => '<strong>Rule wajib:</strong> reusable markup diekstrak ke partial/component setelah dipakai berulang.',
    'pages.skema.layout.step_7' => '<strong>Rule wajib:</strong> perubahan layout global wajib diuji minimal 3 halaman berbeda.',
    'pages.skema.layout.step_8' => '1. Route memanggil view page (contoh: <code>pages.help.pemrograman.skema.layout</code>).',
    'pages.skema.layout.step_9' => '<strong>Rule wajib:</strong> halaman baru harus meng-extend <code>layouts.index</code> kecuali ada alasan arsitektural.',
    'pages.skema.layout.warn_1' => 'Hindari menaruh script berat global di semua halaman jika hanya dipakai satu halaman.',
    'pages.skema.pemilihan-bahasa.chip_1' => 'locale default: en',
