    'pages.skema.pemilihan-bahasa.heading_4' => 'Pola Translasi Menu Dinamis',
    'pages.skema.pemilihan-bahasa.heading_5' => 'Whitelist Locale',
    'pages.skema.pemilihan-bahasa.heading_6' => 'Tambah Bahasa Baru (contoh: ja)',
    'pages.skema.pemilihan-bahasa.heading_7' => 'Edge Cases dan Debug Checklist',
    'pages.skema.pemilihan-bahasa.heading_8' => 'Standar Tim (Strict) Locale Switch',
    'pages.skema.pemilihan-bahasa.heading_9' => 'Checklist Validasi Tambah Locale Baru',
    'pages.skema.pemilihan-bahasa.item_1' => '<code>routes/web.php</code>: endpoint switch locale <code>/lang/{locale}</code>.',
    'pages.skema.pemilihan-bahasa.item_10' => 'Jika key tidak tersedia, renderer fallback ke text title asli.',
    'pages.skema.pemilihan-bahasa.item_11' => 'Buat <code>lang/ja/menu.php</code>.',
    'pages.skema.pemilihan-bahasa.item_12' => 'Update whitelist locale jadi <code>[\'en\', \'id\', \'ja\']</code>.',
    'pages.skema.pemilihan-bahasa.item_13' => 'Tambah opsi language selector di user menu.',
    'pages.skema.pemilihan-bahasa.item_14' => 'Tambah key label bahasa baru pada menu translation.',
    'pages.skema.pemilihan-bahasa.item_15' => 'Uji perpindahan bahasa dan cek key yang belum terisi.',
    'pages.skema.pemilihan-bahasa.item_16' => '<code>redirect()->back()</code> bergantung referer; tanpa referer perilaku redirect bisa berbeda.',
    'pages.skema.pemilihan-bahasa.item_17' => 'File translasi yang tidak sinkron antar locale menimbulkan UI campuran bahasa.',
    'pages.skema.pemilihan-bahasa.item_18' => 'Cache aktif dapat membuat perubahan bahasa terlihat terlambat.',
    'pages.skema.pemilihan-bahasa.item_19' => 'Menu utama tertranslate penuh tanpa key mentah tampil.',
    'pages.skema.pemilihan-bahasa.item_2' => '<code>app/Http/Middleware/SetLocale.php</code>: baca session locale dan set ke runtime.',
    'pages.skema.pemilihan-bahasa.item_20' => 'Halaman auth/error/validation tidak campur bahasa.',
    'pages.skema.pemilihan-bahasa.item_21' => 'Switch locale tetap konsisten setelah login/logout.',
    'pages.skema.pemilihan-bahasa.item_22' => 'Tidak ada overflow layout pada teks lebih panjang.',
    'pages.skema.pemilihan-bahasa.item_3' => '<code>bootstrap/app.php</code>: registrasi middleware <code>SetLocale</code> pada group <code>web</code>.',
    'pages.skema.pemilihan-bahasa.item_4' => '<code>resources/views/partials/menus/_user-account-menu.blade.php</code>: UI selector bahasa.',
    'pages.skema.pemilihan-bahasa.item_5' => '<code>config/app.php</code>: default locale dan fallback locale.',
    'pages.skema.pemilihan-bahasa.item_6' => 'Session kosong -> pakai <code>config(\'app.locale\')</code> (default <code>en</code>).',
    'pages.skema.pemilihan-bahasa.item_7' => 'Key tidak ada -> fallback ke <code>config(\'app.fallback_locale\')</code>.',
    'pages.skema.pemilihan-bahasa.item_8' => 'Jika tetap tidak ada -> key mentah bisa tampil di UI.',
    'pages.skema.pemilihan-bahasa.item_9' => 'Sumber string: <code>lang/en/menu.php</code> dan <code>lang/id/menu.php</code>.',
    'pages.skema.pemilihan-bahasa.lead' => 'Locale dipilih dari user menu, disimpan di session, lalu diterapkan oleh middleware web pada setiap request.',
    'pages.skema.pemilihan-bahasa.note_1' => 'Checklist cepat: cek session locale -> cek middleware terpasang -> cek key translation -> clear cache.',
    'pages.skema.pemilihan-bahasa.step_1' => '2. Link menuju <code>route(\'lang.switch\', \'{locale}\')</code>.',
    'pages.skema.pemilihan-bahasa.step_10' => '1. User klik English / Indonesian di user account menu.',
    'pages.skema.pemilihan-bahasa.step_11' => '<strong>Rule wajib:</strong> locale switch harus melalui whitelist eksplisit, tidak menerima input bebas.',
    'pages.skema.pemilihan-bahasa.step_2' => '3. Route <code>/lang/{locale}</code> validasi whitelist locale.',
    'pages.skema.pemilihan-bahasa.step_3' => '4. Locale valid disimpan dengan <code>session([\'locale\' => $locale])</code>.',
    'pages.skema.pemilihan-bahasa.step_4' => '5. Redirect kembali ke halaman sebelumnya.',
    'pages.skema.pemilihan-bahasa.step_5' => '6. Middleware <code>SetLocale</code> menjalankan <code>App::setLocale()</code>.',
    'pages.skema.pemilihan-bahasa.step_6' => '7. Seluruh <code>__()</code> membaca file bahasa sesuai locale aktif.',
    'pages.skema.pemilihan-bahasa.step_7' => '<strong>Rule wajib:</strong> saat menambah locale baru, update route whitelist + UI selector + file lang domain utama.',
    'pages.skema.pemilihan-bahasa.step_8' => '<strong>Rule wajib:</strong> fallback locale harus tetap terdefinisi untuk mencegah UI kosong.',
    'pages.skema.pemilihan-bahasa.step_9' => '<strong>Rule wajib:</strong> perubahan locale harus teruji lintas halaman dan lintas role user.',
    'pages.skema.pemilihan-bahasa.warn_1' => 'Saat menambah bahasa baru, whitelist wajib diperbarui. Jika tidak, locale baru tidak akan tersimpan.',
    'pages.skema.route.chip_1' => 'Source of truth: folder structure',
