    'pages.skema.route.heading_1' => 'Flow Request',
    'pages.skema.route.heading_2' => 'Konversi File ke Route',
    'pages.skema.route.heading_3' => 'Komponen Tanggung Jawab',
    'pages.skema.route.heading_4' => 'Quick Add Page',
    'pages.skema.route.heading_5' => 'Contoh Pemetaan Aktual',
    'pages.skema.route.heading_6' => 'Prioritas Evaluasi Route',
    'pages.skema.route.heading_7' => 'Standar Tim (Strict) Route',
    'pages.skema.route.heading_8' => 'Troubleshooting Route',
    'pages.skema.route.item_1' => '<code>routes/web.php</code>: route khusus, auth, profile, language switch, bootstrap route lain.',
    'pages.skema.route.item_10' => 'Pada proyek ini, <code>routes/menu.php</code> dan <code>fallback</code> memegang peran besar untuk halaman konten.',
    'pages.skema.route.item_11' => '<strong>Route tidak ditemukan:</strong> cek penamaan file blade dan lokasi di <code>resources/views/pages</code>.',
    'pages.skema.route.item_12' => '<strong>Route ada tapi tidak bisa diakses:</strong> cek middleware auth/verified dan status login.',
    'pages.skema.route.item_13' => '<strong>Perubahan route belum terbaca:</strong> jalankan clear/cache command sesuai environment.',
    'pages.skema.route.item_14' => '<strong>Nama route bentrok:</strong> cek hasil <code>php artisan route:list</code> untuk duplikasi.',
